}Step 6: Add Tone Refinement
jsx
async function handleToneRefinement(selectedText: string, tone: string) {
const response = await fetch('/api/ai', {
method: 'POST',
body: JSON.stringify({
prompt: `Rewrite this in a ${tone} tone: ${selectedText}`,
tone,
}),
});
const reader = response.body?.getReader();
let result = '';
while (reader) {
const { done, value } = await reader.read();
if (done) break;
result += new TextDecoder().decode(value);
}
editor?.commands.insertContent(result);
}Step 7: Add Autocomplete (Copilot-Style Ghost Text)
Ghost text is more complex than chat — you need to detect typing pauses and insert semi-transparent suggestions.
jsx
"use client";
import { useEffect, useState } from 'react';
import { useDebouncedCallback } from 'use-debounce';
function useAutocomplete(editor) {
const [ghostText, setGhostText] = useState('');
const fetchSuggestion = useDebouncedCallback(async (context: string) => {
if (!context || context.length < 20) return;
const response = await fetch('/api/ai', {
method: 'POST',
body: JSON.stringify({
prompt: `Continue writing this text (short continuation, 1-2 sentences): ${context}`,
}),
});
const reader = response.body?.getReader();
let suggestion = '';
while (reader) {
const { done, value } = await reader.read();
if (done) break;
suggestion += new TextDecoder().decode(value);
}
setGhostText(suggestion);
}, 800);
useEffect(() => {
if (!editor) return;
editor.on('update', () => {
const text = editor.getText();
fetchSuggestion(text);
});
}, [editor, fetchSuggestion]);
const acceptSuggestion = () => {
if (ghostText) {
editor?.commands.insertContent(ghostText);
setGhostText('');
}
};
return { ghostText, acceptSuggestion };
}Plan for 2–3 days total including UI polish, prompt engineering iteration, and cost controls (rate limiting to prevent runaway OpenAI API bills).
